module shift_register(reset_clk, rst, data, q);

    input  reset_clk;
    input  rst;
    input  data;
    output reg [7:0] q;

    always @(posedge reset_clk or posedge rst) begin
        if (rst)
            q <= 8'b00000000;
        else
            q <= {q[6:0], data};
    end

endmodule
